This test exercises the CLI executable described in prompt.md. Per the kata spec:
- The CLI entry point must be at `src/cli.ts`
- It reads a JSON scenario from stdin and writes results JSON to stdout
- For an unknown item type (e.g. {type: "broomstick"}), the CLI must exit with non-zero status and write an error description to stderr; no `results` are written to stdout

The test should:
1. Spawn the CLI via tsx (use `node:child_process` spawnSync, with `npx tsx src/cli.ts` or `node --import tsx src/cli.ts`). Use this command: `process.execPath` with args `["--import", "tsx", "src/cli.ts"]` from the project root, OR use `tsx src/cli.ts` via spawnSync.
2. Pass JSON input on stdin: a scenario with a quote step containing an item of type "broomstick"
3. Assert: exitCode !== 0, stderr is non-empty, stdout does not contain "results"

Suggested test code:
```ts
import { spawnSync } from "node:child_process";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

// helper at top of describe or as standalone function:
function runCli(input: unknown) {
  const projectRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");
  const result = spawnSync("npx", ["tsx", "src/cli.ts"], {
    cwd: projectRoot,
    input: JSON.stringify(input),
    encoding: "utf8",
  });
  return result;
}

it("quote with unknown item type causes the CLI to exit with non-zero status and error to stderr", () => {
  const result = runCli({
    customer: { yearsWithMHPCO: 0 },
    steps: [{ op: "quote", items: [{ type: "broomstick" }] }],
  });
  expect(result.status).not.toBe(0);
  expect(result.stderr).not.toBe("");
  expect(result.stdout).not.toContain("results");
});
```

